import { useState, useCallback, type Dispatch, type SetStateAction } from 'react'
import type { HarmonySortColumn, HarmonyPagination } from '@/components/ui/harmony-table'
import { DEFAULT_PAGE_SIZE } from '@/components/ui/harmony-table'

export interface UseHarmonyServerTableOptions<TFilters extends Record<string, string> = Record<string, string>> {
  defaultFilters?: Partial<TFilters>
  defaultPageSize?: number
  defaultRefreshInterval?: number
}

export interface UseHarmonyServerTableResult<TFilters extends Record<string, string> = Record<string, string>> {
  // State — use in queryKey + queryFn params
  filterValues: TFilters
  pageIndex: number
  pageSize: number
  sort: string | undefined
  sortOrder: 'Ascending' | 'Descending' | undefined
  sortColumns: HarmonySortColumn[]
  autoRefresh: boolean
  refreshInterval: number

  // HarmonyTable prop handlers
  onFilterChange: (params: Record<string, string>) => void
  onSortColumnsChange: (cols: HarmonySortColumn[]) => void
  setAutoRefresh: Dispatch<SetStateAction<boolean>>
  setRefreshInterval: Dispatch<SetStateAction<number>>
  setPageIndex: Dispatch<SetStateAction<number>>
  setPageSize: Dispatch<SetStateAction<number>>

  /**
   * Builds the HarmonyTable `pagination` prop from an API response.
   * Pass the query `data` directly — all fields are optional so it works
   * before the first response arrives.
   */
  getPagination: (data?: {
    totalCount?: number
    totalPages?: number
    hasPreviousPage?: boolean
    hasNextPage?: boolean
  }) => HarmonyPagination
}

/**
 * Manages all server-table state in one place: filters, pagination, sort, and
 * auto-refresh. Use the returned values as React Query `queryKey` entries and
 * pass the handlers directly to HarmonyTable props.
 *
 * @example
 * ```ts
 * interface LogsFilters { level: string; timeRange: string }
 *
 * const server = useHarmonyServerTable<LogsFilters>({
 *   defaultFilters: { timeRange: 'last1day' },
 * })
 *
 * const { data } = useQuery({
 *   queryKey: ['logs', server.filterValues, server.sort, server.sortOrder, server.pageIndex, server.pageSize],
 *   queryFn:  () => logService.getLogs({ ...server.filterValues, sort: server.sort, ... }),
 *   refetchInterval: server.autoRefresh ? server.refreshInterval * 1000 : false,
 * })
 *
 * return (
 *   <HarmonyTable
 *     filterValues={server.filterValues}
 *     onFilterChange={server.onFilterChange}
 *     sortColumns={server.sortColumns}
 *     onSortColumnsChange={server.onSortColumnsChange}
 *     pagination={server.getPagination(data)}
 *     dataActions={{
 *       onReload: () => refetch(),
 *       autoRefresh: { enabled: server.autoRefresh, interval: server.refreshInterval,
 *                      onToggle: server.setAutoRefresh, onIntervalChange: server.setRefreshInterval },
 *     }}
 *   />
 * )
 * ```
 */
export function useHarmonyServerTable<
  TFilters extends Record<string, string> = Record<string, string>,
>({
  defaultFilters,
  defaultPageSize = DEFAULT_PAGE_SIZE,
  defaultRefreshInterval = 10,
}: UseHarmonyServerTableOptions<TFilters> = {}): UseHarmonyServerTableResult<TFilters> {
  const [filterValues,    setFilterValues]    = useState<TFilters>((defaultFilters ?? {}) as TFilters)
  const [pageIndex,       setPageIndex]       = useState(1)
  const [pageSize,        setPageSize]        = useState(defaultPageSize)
  const [sort,            setSort]            = useState<string | undefined>(undefined)
  const [sortOrder,       setSortOrder]       = useState<'Ascending' | 'Descending' | undefined>(undefined)
  const [sortColumns,     setSortColumns]     = useState<HarmonySortColumn[]>([])
  const [autoRefresh,     setAutoRefresh]     = useState(false)
  const [refreshInterval, setRefreshInterval] = useState(defaultRefreshInterval)

  const onFilterChange = useCallback((params: Record<string, string>) => {
    setFilterValues(params as TFilters)
    setPageIndex(1)
  }, [])

  const onSortColumnsChange = useCallback((cols: HarmonySortColumn[]) => {
    setSortColumns(cols)
    const first = cols[0]
    setSort(first?.sortParam ?? first?.columnKey)
    setSortOrder(first ? (first.direction === 'ASC' ? 'Ascending' : 'Descending') : undefined)
    setPageIndex(1)
  }, [])

  const getPagination = useCallback((data?: {
    totalCount?: number
    totalPages?: number
    hasPreviousPage?: boolean
    hasNextPage?: boolean
  }): HarmonyPagination => ({
    pageSize,
    currentPage:     pageIndex,
    totalCount:      data?.totalCount,
    totalPages:      data?.totalPages,
    hasPreviousPage: data?.hasPreviousPage,
    hasNextPage:     data?.hasNextPage,
    onPageChange:    setPageIndex,
    onPageSizeChange: (s) => { setPageSize(s); setPageIndex(1) },
  }), [pageIndex, pageSize])

  return {
    filterValues,
    pageIndex,
    pageSize,
    sort,
    sortOrder,
    sortColumns,
    autoRefresh,
    refreshInterval,
    onFilterChange,
    onSortColumnsChange,
    setAutoRefresh,
    setRefreshInterval,
    setPageIndex,
    setPageSize,
    getPagination,
  }
}
